import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as l,f as e,a as s,e as p,d as o}from"./app-38e63990.js";const c={},t=s("blockquote",null,[s("p",null,[s("code",null,"xv6"),p(" 的多线程")])],-1),r=o(`<h1 id="lab06-multithreading" tabindex="-1"><a class="header-anchor" href="#lab06-multithreading" aria-hidden="true">#</a> Lab06 Multithreading</h1><p>一个模拟多线程的实验，应该算是比较简单的实验，可以仿照原有的实现来做。</p><p>实验难度为三个 <code>moderate</code></p><h2 id="实验准备" tabindex="-1"><a class="header-anchor" href="#实验准备" aria-hidden="true">#</a> 实验准备</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">git</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">fetch</span></span>
<span class="line"><span style="color:#61AFEF;">git</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">checkout</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">thread</span></span>
<span class="line"><span style="color:#61AFEF;">make</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">clean</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>得到相应的实验环境</p><h2 id="uthread-switching-between-threads" tabindex="-1"><a class="header-anchor" href="#uthread-switching-between-threads" aria-hidden="true">#</a> Uthread: switching between threads</h2><p>实验要求补全 <code>uthread.c</code> 与 <code>uthread_switch.S</code> 中的代码，完成一份用户层面的线程切换。</p><p>我们可以仿照 <code>kernel/proc.c</code> 中 <code>sched()</code> 与 <code>kernel/swtch.S</code> 的实现。</p><p>首先我们知道，调度不能缺少上下文，于是我们仿照 <code>kernel/proc.h</code> 中上下文的定义，并在 <code>struct thread</code> 中加入上下文：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">struct</span><span style="color:#ABB2BF;"> thread_context {</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 ra;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 sp;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#7F848E;font-style:italic;">// callee-saved</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s0;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s1;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s2;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s3;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s4;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s5;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s6;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s7;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s8;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s9;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s10;</span></span>
<span class="line"><span style="color:#ABB2BF;">  uint64 s11;</span></span>
<span class="line"><span style="color:#ABB2BF;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">struct</span><span style="color:#ABB2BF;"> thread {</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">char</span><span style="color:#ABB2BF;">       </span><span style="color:#E06C75;">stack</span><span style="color:#ABB2BF;">[STACK_SIZE];</span><span style="color:#7F848E;font-style:italic;"> /* the thread&#39;s stack */</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">int</span><span style="color:#ABB2BF;">        state;</span><span style="color:#7F848E;font-style:italic;">             /* FREE, RUNNING, RUNNABLE */</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">struct</span><span style="color:#ABB2BF;"> thread_context context;</span><span style="color:#7F848E;font-style:italic;"> /* the thread&#39;s context */</span></span>
<span class="line"><span style="color:#ABB2BF;">};</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>随后，我们想知道，用户级别的线程中我们如何获取 <code>ra</code> 与 <code>sp</code> （也就是返回地址与栈指针）</p><p>在 <code>thread_create()</code> 中，我们发现传递进来的是一个函数指针（也就是这个线程需要完成的工作），那么显然，我们应该把这个地址设置为我们的 <code>ra</code> ，并且我们发现，在 <code>struct thread</code> 的定义中有着 <code>stack</code>的定义，于是我们也能获取线程的栈指针了：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">void</span></span>
<span class="line"><span style="color:#61AFEF;">thread_create</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">void</span><span style="color:#E06C75;"> </span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">*</span><span style="color:#E06C75;">func</span><span style="color:#ABB2BF;">)()) {</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">struct</span><span style="color:#ABB2BF;"> thread</span><span style="color:#C678DD;">*</span><span style="color:#ABB2BF;"> t;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">for</span><span style="color:#ABB2BF;"> (t </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> all_thread; t </span><span style="color:#C678DD;">&lt;</span><span style="color:#ABB2BF;"> all_thread </span><span style="color:#C678DD;">+</span><span style="color:#ABB2BF;"> MAX_THREAD; t</span><span style="color:#C678DD;">++</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E5C07B;">t</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E06C75;">state</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">==</span><span style="color:#ABB2BF;"> FREE) </span><span style="color:#C678DD;">break</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E5C07B;">t</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E06C75;">state</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> RUNNABLE;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  /* YOUR CODE HERE */</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E5C07B;">t</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E5C07B;">context</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">ra</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> (uint64)func;</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E5C07B;">t</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E5C07B;">context</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">sp</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> </span><span style="color:#E5C07B;">t</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E5C07B;">context</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">s0</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> (uint64)</span><span style="color:#C678DD;">&amp;</span><span style="color:#E5C07B;">t</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E06C75;">stack</span><span style="color:#ABB2BF;">[STACK_SIZE </span><span style="color:#C678DD;">-</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">];</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>值得注意的是，这里的 <code>s0</code> 实际上就是 <code>fp</code>（<code>frame pointer</code>），与栈指针指向相同的地方，并且我们需要注意，栈是从高地址向低地址增长的，所以这里应该取数组最末尾的地址。</p><p>这样，我们就完成了上下文的创建，接下来就是上下文的切换了。我们仿照 <code>kernel/swtch.S</code> 中的实现：</p><div class="language-asm line-numbers-mode" data-ext="asm"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">	</span><span style="color:#61AFEF;">.text</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">	</span><span style="color:#7F848E;font-style:italic;">/*</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">         * save the old thread&#39;s registers,</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">         * restore the new thread&#39;s registers.</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">         */</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">	.globl thread_switch</span></span>
<span class="line"><span style="color:#61AFEF;">thread_switch:</span></span>
<span class="line"><span style="color:#ABB2BF;">	</span><span style="color:#7F848E;font-style:italic;">/* YOUR CODE HERE */</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd ra, </span><span style="color:#C678DD;">0</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd </span><span style="color:#D19A66;">sp</span><span style="color:#ABB2BF;">, </span><span style="color:#C678DD;">8</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s0, </span><span style="color:#C678DD;">16</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s1, </span><span style="color:#C678DD;">24</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s2, </span><span style="color:#C678DD;">32</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s3, </span><span style="color:#C678DD;">40</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s4, </span><span style="color:#C678DD;">48</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s5, </span><span style="color:#C678DD;">56</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s6, </span><span style="color:#C678DD;">64</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s7, </span><span style="color:#C678DD;">72</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s8, </span><span style="color:#C678DD;">80</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s9, </span><span style="color:#C678DD;">88</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s10, </span><span style="color:#C678DD;">96</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"><span style="color:#ABB2BF;">    sd s11, </span><span style="color:#C678DD;">104</span><span style="color:#ABB2BF;">(a0)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">    ld ra, </span><span style="color:#C678DD;">0</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld </span><span style="color:#D19A66;">sp</span><span style="color:#ABB2BF;">, </span><span style="color:#C678DD;">8</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s0, </span><span style="color:#C678DD;">16</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s1, </span><span style="color:#C678DD;">24</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s2, </span><span style="color:#C678DD;">32</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s3, </span><span style="color:#C678DD;">40</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s4, </span><span style="color:#C678DD;">48</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s5, </span><span style="color:#C678DD;">56</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s6, </span><span style="color:#C678DD;">64</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s7, </span><span style="color:#C678DD;">72</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s8, </span><span style="color:#C678DD;">80</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s9, </span><span style="color:#C678DD;">88</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s10, </span><span style="color:#C678DD;">96</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    ld s11, </span><span style="color:#C678DD;">104</span><span style="color:#ABB2BF;">(a1)</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span></span>
<span class="line"><span style="color:#ABB2BF;">	</span><span style="color:#C678DD;">ret</span><span style="color:#ABB2BF;">    </span><span style="color:#7F848E;font-style:italic;">/* return to ra */</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在用户级代码中，我们在 <code>thread_schedule()</code> 中对两个线程进行切换：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> (current_thread </span><span style="color:#C678DD;">!=</span><span style="color:#ABB2BF;"> next_thread) {</span><span style="color:#7F848E;font-style:italic;">         /* switch threads?  */</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E5C07B;">next_thread</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E06C75;">state</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> RUNNING;</span></span>
<span class="line"><span style="color:#ABB2BF;">    t </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> current_thread;</span></span>
<span class="line"><span style="color:#ABB2BF;">    current_thread </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> next_thread;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">    /* YOUR CODE HERE</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">     * Invoke thread_switch to switch from t to next_thread:</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">     * thread_switch(??, ??);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">     */</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">thread_switch</span><span style="color:#ABB2BF;">((uint64)</span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;">t, (uint64)</span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;">current_thread);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里注意两点：</p><ol><li><code>t</code> 是需要让出 <code>CPU</code> 的线程，而 <code>current_thread</code> 或者说 <code>next_thread</code> 是需要被恢复运行的线程，根据我们在 <code>uthread_switch.S</code> 中的实现知道，第一个参数应该是需要保存上下文的线程，第二个是需要被恢复的线程。</li><li>注意，我们需要切换的上下文，所以在这里我不能写成 <code>thread_switch((uint64)t, (uint64)current_thread)</code>，这会导致系统出错（因为<code>thread</code> 里面的 <code>ra</code> 什么的和我们定义的 <code>thread_context</code> 是不一样的……）</li></ol><h2 id="using-threads" tabindex="-1"><a class="header-anchor" href="#using-threads" aria-hidden="true">#</a> Using threads</h2><p>要求在真正的 <code>Linux</code> 或者 <code>MacOS</code> 上完成这个实验（<code>WSL2</code>完全可以胜任），因为要使用 <code>pthread</code> 这个库来进行一些多线程编程。</p><p>这里会答应一个问题，就是，为什么我们使用2个线程来完成哈希表的插入的时候，会出现一大堆的 <code>missing</code> 呢？虽然速度是有着显著的提升。</p><p>如果你仔细看 <code>ph.c</code> 中的 <code>put()</code> 与 <code>insert()</code> 的话，我的理解是：</p><blockquote><p>多线程同时修改临界区的数据，可能会造成数据的丢失，例如两个线程如果都新插入一个条目的话，因为是异步的，所以可能会造成不同线程之间没有任何协同，导致前面刚插进去的东西，后一步就直接连到应该NULL上面去了，这样就会丢失很多数据，导致后面整个哈希表可能都是NULL</p></blockquote><p>于是，他告诉我们，可以通过使用锁 (<code>mutex</code>) 来避免由于竞争带来的错误，并且我们的速度并不会受到很大的影响。</p><p>那么，我们首先在全局中声明：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">pthread_mutex_t</span><span style="color:#ABB2BF;"> lock;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在 <code>main()</code> 中，我们在创建线程前初始化这个互斥锁：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">  nthread </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> </span><span style="color:#61AFEF;">atoi</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">argv[</span><span style="color:#D19A66;">1</span><span style="color:#E06C75;">]</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#61AFEF;">pthread_mutex_init</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#E06C75;font-style:italic;">lock</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> </span><span style="color:#D19A66;">NULL</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>随后，我们有两种做法（但实际上只有一种）：</p><ol><li><p>我们直接一劳永逸，在 <code>put_thread()</code> 这个线程执行的函数中，我们在 <code>put</code> 前加锁，在完成 <code>put</code> 操作后解锁：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">static</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">void*</span></span>
<span class="line"><span style="color:#61AFEF;">put_thread</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">void*</span><span style="color:#E06C75;"> </span><span style="color:#E06C75;font-style:italic;">xa</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">int</span><span style="color:#ABB2BF;"> n </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> (</span><span style="color:#C678DD;">int</span><span style="color:#ABB2BF;">)(</span><span style="color:#C678DD;">long</span><span style="color:#ABB2BF;">)xa;</span><span style="color:#7F848E;font-style:italic;"> // thread number</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">int</span><span style="color:#ABB2BF;"> b </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> NKEYS </span><span style="color:#C678DD;">/</span><span style="color:#ABB2BF;"> nthread;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">for</span><span style="color:#ABB2BF;"> (</span><span style="color:#C678DD;">int</span><span style="color:#ABB2BF;"> i </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">; i </span><span style="color:#C678DD;">&lt;</span><span style="color:#ABB2BF;"> b; i</span><span style="color:#C678DD;">++</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">pthread_mutex_lock</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;">lock); </span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">put</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">keys</span><span style="color:#ABB2BF;">[b </span><span style="color:#C678DD;">*</span><span style="color:#ABB2BF;"> n </span><span style="color:#C678DD;">+</span><span style="color:#ABB2BF;"> i], n);</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">pthread_mutex_unlock</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;">lock);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">return</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">NULL</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这是一种很朴素的想法，事实上，这种操作下，我们在同一时间只允许一个线程进行 <code>put</code> 操作，这当然不会出错，因为实际上这是一个串行的想法。但这种想法的结果是很糟糕的，因为我们为了不犯任何错误而抛弃了多线程的优势：速度快</p><p>我们可以运行对比一下：</p><figure><img src="https://s2.loli.net/2022/09/06/m2zihRcpGfIda8U.png" alt="Cmp" tabindex="0" loading="lazy"><figcaption>Cmp</figcaption></figure><p>可以发现2个线程运行的居然会比1个线程运行的还慢，这显然是不行的。</p></li><li><p>我们结合上面问题的答案，大概能确定问题应该是出在 <code>insert()</code> 这个函数上，所以我们只需要在 <code>put()</code> 中调用 <code>insert()</code> 的前后加锁即可：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">else</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#7F848E;font-style:italic;">// the new is new.</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">pthread_mutex_lock</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;">lock);</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">insert</span><span style="color:#ABB2BF;">(key, value, </span><span style="color:#C678DD;">&amp;</span><span style="color:#E06C75;">table</span><span style="color:#ABB2BF;">[i], </span><span style="color:#E06C75;">table</span><span style="color:#ABB2BF;">[i]);</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">pthread_mutex_unlock</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;">lock);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样，我们运行后对比为：</p><figure><img src="https://s2.loli.net/2022/09/06/6mQ8uMSwhJYiZH2.png" alt="Cmp" tabindex="0" loading="lazy"><figcaption>Cmp</figcaption></figure><p>很完美</p></li></ol><h2 id="barrier" tabindex="-1"><a class="header-anchor" href="#barrier" aria-hidden="true">#</a> Barrier</h2><p>要求实现一个屏障点，也就是说，只有当所有线程都到达 <code>barrier()</code> 这个函数之后，线程才能够继续运行，提前到达的只能等着。</p><p>这个应该还是比较好实现的：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">static</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">void</span></span>
<span class="line"><span style="color:#61AFEF;">barrier</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#7F848E;font-style:italic;">// YOUR CODE HERE</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#7F848E;font-style:italic;">//</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#7F848E;font-style:italic;">// Block until all threads have called barrier() and</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#7F848E;font-style:italic;">// then increment bstate.round.</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#7F848E;font-style:italic;">//</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#61AFEF;">pthread_mutex_lock</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">barrier_mutex</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">nthread</span><span style="color:#C678DD;">++</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">nthread</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">==</span><span style="color:#ABB2BF;"> nthread) {</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">nthread</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">round</span><span style="color:#C678DD;">++</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">pthread_cond_broadcast</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">barrier_cond</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">else</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#61AFEF;">pthread_cond_wait</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">barrier_cond</span><span style="color:#ABB2BF;">, </span><span style="color:#C678DD;">&amp;</span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">barrier_mutex</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#61AFEF;">pthread_mutex_unlock</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">&amp;</span><span style="color:#E5C07B;">bstate</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">barrier_mutex</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>我们需要记录 <code>bstate.nthread</code> ，当它等于线程数时，我们就将其归零并且让所有线程继续运行，否则让这个线程等待。（记得记录一下 <code>bstate.round</code> ）</p><h2 id="实验结果" tabindex="-1"><a class="header-anchor" href="#实验结果" aria-hidden="true">#</a> 实验结果</h2><figure><img src="https://s2.loli.net/2022/09/06/7NfePJvjxnpDKhA.png" alt="Final Grade" tabindex="0" loading="lazy"><figcaption>Final Grade</figcaption></figure>`,40);function i(B,d){return a(),l("div",null,[t,e("more"),r])}const F=n(c,[["render",i],["__file","xv6-lab6.html.vue"]]);export{F as default};
